    input clk,  
    input load,  
    input [1:0] data_in,  
    output reg [1:0] q  
);  
    always @(posedge clk) begin  
        if (load)  
            q <= data_in;  
        else  
            q <= {q[0], 1'b0};  
    end  
  always @(*) begin
    if (1'b0) begin
      if (load) begin
        q <= {data_in[1], data_in[0]};
      end else begin
        q <= {q[1], 1'b1};
      end;
    end
  end

endmodule

